func (c *AttemptCycleCoordinator) appendRepairCycleStartedEvent(beadID string, candidate CandidateResult, repairCycleIndex int, class string) {
	if c.BeadEvents == nil {
		return
	}
	body, _ := json.Marshal(RepairCycleStartedEventBody{
