// CommitTracker commits beads.jsonl if it has uncommitted changes. Acquires
// withTrackerLock so concurrent callers serialize on the parent .git index.
// Callers already holding the lock must use commitTrackerLocked instead —
// the lock is not re-entrant.
func CommitTracker(projectRoot string) error {
	return withTrackerLock(projectRoot, func() error {
		return commitTrackerLocked(projectRoot)
	})
}

// commitTrackerLocked is the body of CommitTracker without the lock
// acquisition. Callers must hold withTrackerLock(projectRoot) before calling.
// Used by Run() to fold tracker commit, checkpoint synthesis, and worktree
// creation into a single critical section so concurrent workers do not race
// on the parent's HEAD ref (regression: niflheim concurrent `ddx work` hit
// "cannot lock ref 'HEAD'" between unlocked CommitTracker and SynthesizeCommit).
func commitTrackerLocked(projectRoot string) error {
	trackerFile := filepath.Join(projectRoot, ".ddx", "beads.jsonl")
	info, err := os.Stat(trackerFile)
	if err != nil {
		if os.IsNotExist(err) {
			return nil
		}
		return fmt.Errorf("checking tracker file: %w", err)
	}
	if info.IsDir() {
		return nil
	}

	out, err := internalgit.Command(context.Background(), projectRoot, "rev-parse", "--is-inside-work-tree").Output()
	if err != nil || strings.TrimSpace(string(out)) != "true" {
		return nil
	}

	msg := fmt.Sprintf("chore: update tracker (execute-bead %s)", time.Now().UTC().Format("20060102T150405"))

	// Re-check inside the lock: a sibling worker may have already
	// committed the tracker changes between our pre-lock check and now.
	diff, err := internalgit.Command(context.Background(), projectRoot, "diff", "--", ".ddx/beads.jsonl").Output()
	if err != nil {
		return fmt.Errorf("checking tracker diff: %w", err)
	}

// ApplyLandingToResult merges a BeadLandingResult's fields into an
// ExecuteBeadResult so callers can output a single unified record. It
// overwrites Outcome, Status, Detail, Reason, PreserveRef, GateResults,
// RequiredExecSummary, and ChecksFile based on the landing decision.
func ApplyLandingToResult(res *ExecuteBeadResult, landing *BeadLandingResult) {
	res.Outcome = landing.Outcome
	res.Reason = landing.Reason
	res.PreserveRef = landing.PreserveRef
	res.GateResults = landing.GateResults
	res.RequiredExecSummary = landing.RequiredExecSummary
	res.ChecksFile = landing.ChecksFile
	res.RatchetEvidence = landing.RatchetEvidence
	res.RatchetSummary = landing.RatchetSummary
	// Re-classify status based on landing outcome and reason.
	res.Status = ClassifyExecuteBeadStatus(landing.Outcome, res.ExitCode, landing.Reason)
	res.Detail = ExecuteBeadStatusDetail(res.Status, landing.Reason, res.Error)
	// Refine failure_mode with landing-level signals. A clean merge clears
	// the field; merge conflict or gate failure overrides the worker-level
	// classification; other preserved outcomes keep the worker's mode.
	res.FailureMode = classifyLandingFailureMode(landing.Outcome, landing.Reason, landing.GateResults, res.FailureMode)
	res.OrchestratorStatus = res.Status
}

// ExtractGoverningIDsFromManifest reads governing artifact IDs from a manifest
// JSON file at manifestAbs (absolute path). Returns nil when the file cannot
// be read. Callers use this to populate BeadLandingOptions.GovernIDs.
func ExtractGoverningIDsFromManifest(manifestAbs string) []string {
	if manifestAbs == "" {
		return nil
	}
	type manifestShape struct {
		Governing []struct {
			ID string `json:"id"`
		} `json:"governing"`
	}
	raw, err := os.ReadFile(manifestAbs)
	if err != nil {
		return nil
	}
	var m manifestShape
	if err := json.Unmarshal(raw, &m); err != nil {
		return nil
	}
	ids := make([]string, 0, len(m.Governing))
	for _, g := range m.Governing {
		if g.ID != "" {
			ids = append(ids, g.ID)
		}
	}
	return ids
}

// RecoverOrphans removes orphaned execute-bead worktrees for a given bead ID.
// This is the parent's responsibility — call it before spawning new workers
// so stale worktrees from crashed previous attempts do not accumulate.
func RecoverOrphans(gitOps GitOps, workDir, beadID string) {
	paths, err := gitOps.WorktreeList(workDir)
	if err != nil {
		return
	}
	// Match by basename prefix so orphans are found regardless of their parent
	// directory (legacy .ddx/ vs new $TMPDIR/ddx-exec-wt/).
	basenamePrefix := ExecuteBeadWtPrefix + beadID + "-"
	orphanRemoved := false
	for _, p := range paths {
		if strings.HasPrefix(filepath.Base(p), basenamePrefix) {
			_ = gitOps.WorktreeRemove(workDir, p)
			orphanRemoved = true
		}
	}
	_ = gitOps.WorktreePrune(workDir)

	// Sweep stale run-state left by crashed workers. Per-attempt records are
	// cleared individually so concurrent attempts for other beads remain visible.
	if states, _ := ReadRunStates(workDir); len(states) > 0 {
		for _, state := range states {
			remove := orphanRemoved && state.BeadID == beadID
			if !remove && state.BeadID == beadID {
				remove = true
			}
			if !remove && state.WorktreePath != "" {
				if _, err := os.Stat(state.WorktreePath); os.IsNotExist(err) {
					remove = true
				}
			}
			if remove {
				_ = ClearRunStateAttempt(workDir, state.AttemptID)
			}
		}
	}
}

