		Correlation:   runtime.Correlation,
		Model:         rcfg.Model(),
		Provider:      rcfg.Provider(),
		ModelRef:      rcfg.ModelRef(),
		Effort:        rcfg.Effort(),
		Timeout:       rcfg.Timeout(),
		WallClock:     rcfg.WallClock(),
		WorkDir:       runtime.WorkDir,
		Permissions:   rcfg.Permissions(),
		SessionLogDir: sessionLogDir,
		Env:           runtime.Env,
	}
	return r.Run(opts)
}

// runnerCapabilities is the test-only equivalent of the retired
// Runner.Capabilities. Production callers use CapabilitiesViaService.
func runnerCapabilities(r *Runner, name string) (*HarnessCapabilities, error) {
	harness, harnessName, err := r.resolveHarness(RunArgs{Harness: name})
	if err != nil {
		return nil, err
	}
	caps := &HarnessCapabilities{
		Harness:             harnessName,
		Available:           true,
		Binary:              harness.Binary,
		ReasoningLevels:     r.resolveReasoningLevels(harnessName, harness),
		Surface:             harness.Surface,
		CostClass:           harness.CostClass,
		IsLocal:             harness.IsLocal,
		ExactPinSupport:     harness.ExactPinSupport,
		SupportsEffort:      harness.EffortFlag != "",
		SupportsPermissions: len(harness.PermissionArgs) > 0,
	}
	if path, err := r.LookPath(harness.Binary); err == nil {
		caps.Path = path
	}
	model := r.resolveModel(RunArgs{}, harnessName)
	if model == "" {
		model = harness.DefaultModel
	}
	if model != "" {
		caps.Model = model
		caps.Models = []string{model}
	}
	return caps, nil
}

// runnerValidateForExecuteLoop is the test-only equivalent of the retired
// Runner.ValidateForExecuteLoop. Production callers use
// ValidateForExecuteLoopViaService.
func runnerValidateForExecuteLoop(r *Runner, harnessName, model, _provider string) error {
	if harnessName == "" {
		return nil
	}
	_, _, err := r.resolveHarness(RunArgs{Harness: harnessName})
	if err != nil {
		return err
	}
	return nil
}

// runnerTestProviderConnectivity is the test-only equivalent of the retired
// Runner.TestProviderConnectivity. Production callers use
// TestProviderConnectivityViaService.
func runnerTestProviderConnectivity(r *Runner, harnessName string, timeout time.Duration) ProviderStatus {
	status := ProviderStatus{Reachable: false}
	if harnessName == "virtual" || harnessName == "agent" {
		status.Reachable = true
		status.CreditsOK = true
		return status
	}
	harness, ok := r.registry.Get(harnessName)
	if !ok {
		status.Error = "unknown harness"
		return status
	}
	if _, err := r.LookPath(harness.Binary); err != nil {
		status.Error = "binary not found"
		return status
	}
	opts := RunArgs{Harness: harnessName, Prompt: "echo ok", Timeout: timeout}
	start := time.Now()
	result, err := r.Run(opts)
	duration := time.Since(start)
	if err != nil {
		status.Error = fmt.Sprintf("probe failed: %v (%.0fs)", err, duration.Seconds())
		errStr := strings.ToLower(err.Error())
		if strings.Contains(errStr, "429") || strings.Contains(errStr, "quota") ||
			strings.Contains(errStr, "credit") || strings.Contains(errStr, "insufficient") {
			status.CreditsOK = false
		}
		return status
	}
	if result.ExitCode != 0 || result.Error != "" {
		errStr := strings.ToLower(result.Error)
		status.Error = fmt.Sprintf("probe failed: %s (%.0fs)", result.Error, duration.Seconds())
		if strings.Contains(errStr, "429") || strings.Contains(errStr, "quota") ||
			strings.Contains(errStr, "credit") || strings.Contains(errStr, "insufficient") {
			status.CreditsOK = false
		}
		return status
	}
	status.Reachable = true
	status.CreditsOK = true
	return status
}

// runQuorumWithConfig is the test-only equivalent of the retired
// RunQuorumWithConfig. Production callers use RunQuorumWithConfigViaService.
func runQuorumWithConfig(run RunFunc, _rcfg config.ResolvedConfig, runtime QuorumRuntime) ([]*Result, error) {
	return RunQuorumWith(run, runtime)
}

package agent

import "strings"

const (
	ReviewFindingClassFixableGap  = "review_fixable_gap"
	ReviewFindingClassMalfunction = "review_malfunction"
)

// ReviewFindingClassification is the strict retry/manual class derived from
// structured review evidence. Rationale is retained for operator context, but
// freeform rationale alone is not evidence and cannot make a result repairable.
type ReviewFindingClassification struct {
	Class                   string
	Evidence                []string
	AutomatedRepairEligible bool
	Reason                  string
}

// ClassifyReviewFindings maps a structured reviewer result to the FEAT-010
// review classes used as the policy boundary before repair or manual routing.
func ClassifyReviewFindings(res *ReviewResult) ReviewFindingClassification {
	if res == nil {
		return reviewClassification(ReviewFindingClassMalfunction, nil, "missing review result", false)
	}

	switch res.Verdict {
	case VerdictApprove, VerdictRequestClarification:
		return ReviewFindingClassification{}
	case VerdictRequestChanges, VerdictBlock:
	default:
		return reviewClassification(ReviewFindingClassMalfunction, nil, "malformed review verdict", false)
	}

	evidence := reviewStructuredEvidence(res)
	if len(evidence) == 0 {
		return reviewClassification(ReviewFindingClassMalfunction, nil, "review lacks structured findings or per-AC evidence", false)
	}

	text := strings.ToLower(strings.Join(evidence, "\n"))
	switch {
	case containsAny(text, ReviewTerminalClassUnsafeOrOutScope, "unsafe", "out of scope", "out-of-scope", "outside scope", "non-scope", "forbidden", "scope change", "destructive"):
		return reviewClassification(ReviewTerminalClassUnsafeOrOutScope, evidence, "", false)
	case containsAny(text, ReviewTerminalClassTooLarge, "too large", "too broad", "decompose", "split this bead", "split the bead", "needs decomposition"):
		return reviewClassification(ReviewTerminalClassTooLarge, evidence, "", false)
	case containsAny(text, ReviewTerminalClassSpecGap, "spec gap", "specification gap", "contradictory", "contradiction", "ambiguous requirement", "requirements are unclear", "unclear requirement"):
		return reviewClassification(ReviewTerminalClassSpecGap, evidence, "", false)
	case containsAny(text, ReviewTerminalClassMissingAcceptance, "missing acceptance", "acceptance criteria missing", "acceptance criterion missing", "unverifiable acceptance", "acceptance is unverifiable"):
		return reviewClassification(ReviewTerminalClassMissingAcceptance, evidence, "", false)
	default:
		return reviewClassification(ReviewFindingClassFixableGap, evidence, "", true)
	}
}

func reviewClassification(class string, evidence []string, reason string, repair bool) ReviewFindingClassification {
	return ReviewFindingClassification{
		Class:                   class,
		Evidence:                append([]string(nil), evidence...),
		AutomatedRepairEligible: repair,
		Reason:                  strings.TrimSpace(reason),
	}
}

func reviewStructuredEvidence(res *ReviewResult) []string {
	if res == nil {
		return nil
	}
	var evidence []string
	for _, ac := range res.PerAC {
		if strings.TrimSpace(ac.Evidence) == "" {
			continue
		}
		parts := []string{ac.Item, ac.Grade, ac.Evidence}
		line := strings.TrimSpace(strings.Join(parts, " "))
		if line != "" {
			evidence = append(evidence, line)
		}
	}
	for _, finding := range res.Findings {
		summary := strings.TrimSpace(finding.Summary)
		if summary == "" {
			continue
		}
		if loc := strings.TrimSpace(finding.Location); loc != "" {
			summary = loc + ": " + summary
		}
		if sev := strings.TrimSpace(finding.Severity); sev != "" {
			summary = sev + ": " + summary
		}
		evidence = append(evidence, summary)
	}
	return evidence
}

var RunStateRefreshInterval = 10 * time.Second

// ExecuteBeadRuntime carries the non-durable plumbing for an execute-bead
// run: per-invocation intent (FromRev, PromptFile, WorkerID) and
// non-serializable injection seams (BeadEvents, Service, AgentRunner).
// Durable knobs (Harness, Model, Provider, Effort,
// ContextBudget, MirrorCfg) live on config.ResolvedConfig and are passed
// via ExecuteBeadWithConfig's rcfg argument.
//
// See SD-024 / TD-024 §Runtime structs and §Stage 3.
type ExecuteBeadRuntime struct {
	FromRev         string // base git revision (default: HEAD)
	PromptFile      string // override prompt file (auto-generated if empty)
	Output          io.Writer
	WorkerID        string // from DDX_WORKER_ID env or caller
	BeadEvents      BeadEventAppender
	BeadCancel      BeadCancelStore // optional: enables operator-cancel mid-attempt poll
	ResourceChecker ExecutionResourceChecker
	Service         agentlib.FizeauService
	AgentRunner     AgentRunner
	// RateLimitMaxWait bounds the per-bead total wait spent on rate-limit
	// retries (ddx-c6e3db02 RateLimitRetryContract / TD-031 §8.4). Zero uses
	// RateLimitRetryDefaultBudget (5 min). Negative disables the wrapper —
	// rate-limit responses fall through to the standard execution_failed path.
	RateLimitMaxWait time.Duration
	// ACCheckRunner, when non-nil, runs ddx bead ac-check for the given bead
	// and attempt after the agent commits, writing ac-check.json to the
	// attempt dir under wtPath. When nil, ac-check is skipped.
	ACCheckRunner func(ctx context.Context, beadID, attemptID, wtPath string) (*accheck.Output, error)
}

// GitOps abstracts the git operations required by the worker.
// Merge is intentionally excluded — that belongs to the parent-side
// orchestrator (OrchestratorGitOps). UpdateRef/DeleteRef are exposed here
// so landing-side helpers (e.g. BuildLandingGateContext) can pin a
// transient ref while running gate evaluation against an ephemeral
// worktree.
type GitOps interface {
	HeadRev(dir string) (string, error)
	ResolveRev(dir, rev string) (string, error)
	WorktreeAdd(dir, wtPath, rev string) error
	WorktreeRemove(dir, wtPath string) error
	WorktreeList(dir string) ([]string, error)
	WorktreePrune(dir string) error
	IsDirty(dir string) (bool, error)
	// SynthesizeCommit stages real file changes (excluding harness noise paths) and
	// commits them using msg as the commit message. Returns (true, nil) when a
	// commit was made, (false, nil) when there was nothing real to commit (all
	// dirty files were noise), and (false, err) on failure.
	SynthesizeCommit(dir, msg string) (bool, error)
	// UpdateRef updates ref in dir to sha. Used by landing helpers to pin a
	// commit so a transient worktree can check it out without racing with
	// other work that might prune it.
	UpdateRef(dir, ref, sha string) error
	// DeleteRef removes ref from dir. Used to unpin a transient ref after
	// the consumer (e.g. an ephemeral worktree) is done with it.
	DeleteRef(dir, ref string) error
}

// AgentRunner runs an agent with the given options.
type AgentRunner interface {
	Run(opts RunArgs) (*Result, error)
}

